const form = $('Trainer Input Form').item.json;
const lessonPlan = $('Lesson Plan Agent').item.json.output;
const assessment = $('Assessment Agent').item.json.output;
const tools = $('Tools & Resources Agent').item.json.output;

const timestamp = new Date().toISOString();

const markdown = `# ${form.Topic}

**Domain:** ${form.Domain}
**WSQ Level:** ${form['WSQ Level']}
**Duration:** ${form['Session Duration (minutes)']} minutes
**Class Size:** ${form['Class Size']}
**Learner Profile:** ${form['Learner Profile']}
**Delivery Mode:** ${form['Delivery Mode']}
**Generated:** ${timestamp}

---

# Part 1: Lesson Plan

${lessonPlan}

---

# Part 2: Assessment Package

${assessment}

---

# Part 3: Tools & Resources

${tools}

---

*Generated by SkillsFuture AI Lesson Planner — an open-source n8n workflow by NERVsystems.*
*Presented at the Institute for Adult Learning (IAL), Singapore.*
`;

return [{
  json: {
    markdown,
    title: `${form.Domain} - ${form.Topic} (${form['WSQ Level']})`,
    metadata: {
      domain: form.Domain,
      topic: form.Topic,
      wsq_level: form['WSQ Level'],
      generated_at: timestamp
    }
  }
}];
